package org.apache.commons.math3.util;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math3.util.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.util.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.util.FastMath;
import static org.junit.Assert.*;

public class StepDefs {
    private double inputValue;
    private double result;

    @Given("the input value is {double}")
    public void the_input_value_is(double value) {
        this.inputValue = value;
    }

    @When("I call FastMath.cosh with the input")
    public void i_call_FastMath_cosh_with_the_input() {
        try {
            this.result = FastMath.cosh(inputValue);
        } catch (Exception e) {
            fail("Exception occurred when calling FastMath.cosh: " + e.getMessage());
        }
    }

    @When("I call FastMath.sinh with the input")
    public void i_call_FastMath_sinh_with_the_input() {
        try {
            this.result = FastMath.sinh(inputValue);
        } catch (Exception e) {
            fail("Exception occurred when calling FastMath.sinh: " + e.getMessage());
        }
    }

    @Then("the result should be finite")
    public void the_result_should_be_finite() {
        assertTrue("Result should be finite but was: " + result, Double.isFinite(result));
    }

    @Then("the result should be approximately {double}")
    public void the_result_should_be_approximately(double expected) {
        assertEquals("Result should be approximately " + expected + " but was: " + result, 
                    expected, result, Math.ulp(expected));
    }

    @Then("the result should match Math.cosh within 1 ULP")
    public void the_result_should_match_Math_cosh_within_1_ULP() {
        double mathCosh = Math.cosh(inputValue);
        double diff = Math.abs(result - mathCosh);
        assertTrue("Result should match Math.cosh within 1 ULP, but difference is: " + diff + 
                  ". FastMath.cosh: " + result + ", Math.cosh: " + mathCosh, 
                  diff <= Math.ulp(mathCosh));
    }

    @Then("the result should match Math.sinh within 1 ULP")
    public void the_result_should_match_Math_sinh_within_1_ULP() {
        double mathSinh = Math.sinh(inputValue);
        double diff = Math.abs(result - mathSinh);
        assertTrue("Result should match Math.sinh within 1 ULP, but difference is: " + diff + 
                  ". FastMath.sinh: " + result + ", Math.sinh: " + mathSinh, 
                  diff <= Math.ulp(mathSinh));
    }
}
